const item = $input.first();
const data = item.json.data;
const pages = data.pages;
if (!pages || !pages.length) return [{ json: { error: 'no pages' } }];
const pagesIndex = data.pagesIndex;
if (!pagesIndex) return [{ json: { error: 'no pagesIndex' } }];

// Ищем страницу "Контент"
let pageId = null;
for (const pid of pages) {
  if (pagesIndex[pid] && pagesIndex[pid].name) {
    const pageName = pagesIndex[pid].name.toLowerCase();
    if (pageName.includes('контент')) {
      pageId = pid;
      break;
    }
  }
}

if (!pageId) {
  const available = pages.map(p => pagesIndex[p]?.name || p).join(', ');
  return [{ json: { error: 'Страница "Контент" не найдена', available } }];
}

const objects = pagesIndex[pageId].objects || {};
const images = [];
for (const [, obj] of Object.entries(objects)) {
  if (!obj || obj.type !== 'image') continue;
  if (!obj.metadata || !obj.metadata.id) continue;
  const name = String(obj.name || '').trim();
  const width = obj.metadata.width;
  const height = obj.metadata.height;
  if (width === 5780 && height === 4624) continue;

  const normalized = name.toLowerCase()
    .replace(/e/g, 'е')
    .replace(/a/g, 'а')
    .replace(/o/g, 'о')
    .replace(/p/g, 'р')
    .replace(/c/g, 'с')
    .replace(/x/g, 'х')
    .replace(/k/g, 'к')
    .replace(/i/g, 'и')
    .replace(/d/g, 'д');

  if (normalized.includes('экран') || normalized.includes('креатив') || name.toLowerCase().includes('ipad') || normalized.includes('ипад')) continue;

  images.push({ json: { name, mediaId: obj.metadata.id, downloadUrl: 'https://penpot.itcomp.site/assets/by-file-media-id/' + obj.metadata.id, width, height } });
}
if (images.length === 0) return [{ json: { status: 'no_matching_images' } }];
return images;

