const item = $json;
const attachments = item.fields?.attachment || [];

function decodeFileName(name) {
  if (!name) return null;
  try { return decodeURIComponent(name.replace(/\+/g, ' ')); } catch (e) { return name; }
}

function getType(name) {
  if (!name) return 'unknown';
  const decoded = decodeFileName(name).toLowerCase();
  if (decoded.includes('креатив') || decoded.includes('creative')) return 'creative';
  if (decoded.includes('дизайн') || decoded.includes('design')) return 'design';
  return 'unknown';
}

let design = null;
let creative = null;

for (const att of attachments) {
  const type = getType(att.name || att.filename || '');
  if (type === 'design' && !design) design = att;
  else if (type === 'creative' && !creative) creative = att;
}

if (!design) design = attachments[0] || null;
if (!creative) creative = attachments[1] || null;

return {
  json: {
    ...item,
    designContent: design ? design.content || null : null,
    designId: design ? design.id || null : null,
    designName: design ? decodeFileName(design.name || design.filename) : null,
    creativeContent: creative ? creative.content || null : null,
    creativeId: creative ? creative.id || null : null,
    creativeName: creative ? decodeFileName(creative.name || creative.filename) : null,
  }
};

const crypto = require('crypto');
const output = $json.output || '';
const items = [];
const VALID_RATIOS = ['1:1','2:3','3:2','3:4','4:3','4:5','5:4','9:16','16:9','21:9'];

let currentScreen = 0;
const lines = output.split('\n');

for (const line of lines) {
  const screenMatch = line.match(/[Ээ]кран\s*(\d+)/i);
  if (screenMatch) {
    currentScreen = parseInt(screenMatch[1], 10);
    continue;
  }

  const match = line.match(/^(?:\d+\.|[-•*])\s*(.+?)(?:\s*\|\s*type:\s*(banner|character))?(?:\s*\|\s*ratio:\s*([\d:]+))?\s*$/);
  if (match) {
    const name = match[1].trim();
    if (name && !name.includes('Экран') && !name.startsWith('*')) {
      const ratio = match[3] && VALID_RATIOS.includes(match[3]) ? match[3] : '1:1';
      items.push({
        name,
        elementType: match[2] || 'banner',
        aspectRatio: ratio,
        screenNumber: currentScreen || 1
      });
    }
  }
}

const pageUuid = crypto.randomUUID();

const result = [
  {
    json: {
      name: 'App Icon',
      index: 0,
      pageUuid,
      pageName: 'Контент',
      elementType: 'icon',
      aspectRatio: '1:1',
      screenNumber: 0
    }
  }
];

items.forEach((item, i) => {
  result.push({
    json: {
      name: item.name,
      index: i + 1,
      pageUuid,
      pageName: 'Контент',
      elementType: item.elementType,
      aspectRatio: item.aspectRatio,
      screenNumber: item.screenNumber + 1
    }
  });
});

return result;

